#include <iostream>
#include <unordered_set>
#include <string>

class Solution {
public:
    int countWinningSequences(std::string s) {
        int n = s.length();
        std::unordered_set<char> creatures;

        for (char c : s) {
            creatures.insert(c);
        }

        int result = 0;
        for (int i = 0; i < n; i++) {
            if (creatures.find('F') != creatures.end()) {
                creatures.erase('F');
            }
            if (creatures.find('W') != creatures.end()) {
                creatures.erase('W');
            }
            if (creatures.find('E') != creatures.end()) {
                creatures.erase('E');
            }
        }
        result += 2 * n;
        return result % 1000000007;
    }
};
